// Bricolage Grotesque ExtraBold (800) — embedded as base64 to avoid fs/native deps in edge runtime
const BRICOLAGE_GROTESQUE_800_B64 = '';

export function getBricolageFont(): ArrayBuffer {
  const binary = atob(BRICOLAGE_GROTESQUE_800_B64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}
